import "sort"

type point struct{ x, y int }

func cross(o, a, b point) int64 {
	return int64(a.x-o.x)*int64(b.y-o.y) - int64(a.y-o.y)*int64(b.x-o.x)
}

// ConvexHullCount returns the number of points on the convex hull.
func ConvexHullCount(arr []int) int {
	n := arr[0]
	if n <= 2 { return n }

	points := make([]point, n)
	idx := 1
	for i := 0; i < n; i++ {
		points[i] = point{arr[idx], arr[idx+1]}
		idx += 2
	}
	sort.Slice(points, func(i, j int) bool {
		if points[i].x != points[j].x { return points[i].x < points[j].x }
		return points[i].y < points[j].y
	})

	hull := make([]point, 0, 2*n)
	for _, p := range points {
		for len(hull) >= 2 && cross(hull[len(hull)-2], hull[len(hull)-1], p) <= 0 { hull = hull[:len(hull)-1] }
		hull = append(hull, p)
	}
	lower := len(hull) + 1
	for i := n - 2; i >= 0; i-- {
		for len(hull) >= lower && cross(hull[len(hull)-2], hull[len(hull)-1], points[i]) <= 0 { hull = hull[:len(hull)-1] }
		hull = append(hull, points[i])
	}
	return len(hull) - 1
}

import java.util.Arrays;

public class ConvexHull {

    public static int convexHullCount(int[] arr) {
        int n = arr[0];
        if (n <= 2) return n;

        int[][] points = new int[n][2];
        int idx = 1;
        for (int i = 0; i < n; i++) {
            points[i][0] = arr[idx++];
            points[i][1] = arr[idx++];
        }
        Arrays.sort(points, (a, b) -> a[0] != b[0] ? a[0] - b[0] : a[1] - b[1]);

        int[][] hull = new int[2 * n][2];
        int k = 0;

        for (int i = 0; i < n; i++) {
            while (k >= 2 && cross(hull[k-2], hull[k-1], points[i]) <= 0) k--;
            hull[k++] = points[i];
        }

        int lower = k + 1;
        for (int i = n - 2; i >= 0; i--) {
            while (k >= lower && cross(hull[k-2], hull[k-1], points[i]) <= 0) k--;
            hull[k++] = points[i];
        }

        return k - 1;
    }

    private static long cross(int[] o, int[] a, int[] b) {
        return (long)(a[0] - o[0]) * (b[1] - o[1]) - (long)(a[1] - o[1]) * (b[0] - o[0]);
    }
}

fun convexHullCount(arr: IntArray): Int {
    val n = arr[0]
    if (n <= 2) return n

    data class Pt(val x: Int, val y: Int) : Comparable<Pt> {
        override fun compareTo(other: Pt) = if (x != other.x) x - other.x else y - other.y
    }

    fun cross(o: Pt, a: Pt, b: Pt): Long =
        (a.x - o.x).toLong() * (b.y - o.y) - (a.y - o.y).toLong() * (b.x - o.x)

    val points = mutableListOf<Pt>()
    var idx = 1
    for (i in 0 until n) { points.add(Pt(arr[idx], arr[idx + 1])); idx += 2 }
    points.sort()

    val hull = mutableListOf<Pt>()
    for (p in points) {
        while (hull.size >= 2 && cross(hull[hull.size - 2], hull[hull.size - 1], p) <= 0) hull.removeAt(hull.size - 1)
        hull.add(p)
    }
    val lower = hull.size + 1
    for (i in n - 2 downTo 0) {
        while (hull.size >= lower && cross(hull[hull.size - 2], hull[hull.size - 1], points[i]) <= 0) hull.removeAt(hull.size - 1)
        hull.add(points[i])
    }
    return hull.size - 1
}

def convex_hull_count(arr: list[int]) -> int:
    n = arr[0]
    if n <= 2:
        return n

    points: list[tuple[int, int]] = []
    idx = 1
    for _ in range(n):
        points.append((arr[idx], arr[idx + 1]))
        idx += 2

    points.sort()

    def cross(o: tuple[int, int], a: tuple[int, int], b: tuple[int, int]) -> int:
        return (a[0] - o[0]) * (b[1] - o[1]) - (a[1] - o[1]) * (b[0] - o[0])

    lower: list[tuple[int, int]] = []
    for p in points:
        while len(lower) >= 2 and cross(lower[-2], lower[-1], p) <= 0:
            lower.pop()
        lower.append(p)

    upper: list[tuple[int, int]] = []
    for p in reversed(points):
        while len(upper) >= 2 and cross(upper[-2], upper[-1], p) <= 0:
            upper.pop()
        upper.append(p)

    hull = lower[:-1] + upper[:-1]
    return len(hull)

pub fn convex_hull_count(arr: &[i32]) -> i32 {
    let n = arr[0] as usize;
    if n <= 2 { return n as i32; }

    let mut points: Vec<(i32, i32)> = Vec::new();
    let mut idx = 1;
    for _ in 0..n {
        points.push((arr[idx], arr[idx + 1]));
        idx += 2;
    }
    points.sort();

    fn cross(o: (i32, i32), a: (i32, i32), b: (i32, i32)) -> i64 {
        (a.0 as i64 - o.0 as i64) * (b.1 as i64 - o.1 as i64) - (a.1 as i64 - o.1 as i64) * (b.0 as i64 - o.0 as i64)
    }

    let mut hull: Vec<(i32, i32)> = Vec::new();
    for &p in &points {
        while hull.len() >= 2 && cross(hull[hull.len()-2], hull[hull.len()-1], p) <= 0 { hull.pop(); }
        hull.push(p);
    }
    let lower = hull.len() + 1;
    for i in (0..n-1).rev() {
        while hull.len() >= lower && cross(hull[hull.len()-2], hull[hull.len()-1], points[i]) <= 0 { hull.pop(); }
        hull.push(points[i]);
    }
    (hull.len() - 1) as i32
}

